const health = $('Health: Run research-health').item.json || {};
const stats = $('Health: Run research-stats').item.json || {};
const healthOutput = (health.stdout || '').toString();
const statsOutput = (stats.stdout || '').toString();
const healthExitCode = health.exitCode || 0;
const statsExitCode = stats.exitCode || 0;
const hasAlert = healthOutput.toLowerCase().includes('red') || healthOutput.toLowerCase().includes('critical') || healthOutput.toLowerCase().includes('fail') || healthOutput.toLowerCase().includes('pipeline_failed') || healthOutput.toLowerCase().includes('error') || healthExitCode !== 0 || statsExitCode !== 0;
return [{ json: { command: 'research-health', status: hasAlert ? 'alert' : 'ok', healthExitCode, statsExitCode, healthOutput: healthOutput.substring(0, 1200), statsOutput: statsOutput.substring(0, 800), timestamp: new Date().toISOString() } }];
